/* ---------- hover zoom (escritorio) + toque (móvil) ---------- */
const prev=$('cover-preview');
let previewPinned=false, previewFor=null;
function buildPreview(cover){
  prev.innerHTML='';
  const img=cover.querySelector('img');
  if(img){
    const big=new Image();
    big.src=img.src.replace('-M.jpg','-L.jpg');
    big.onerror=()=>{big.src=img.src;};
    prev.appendChild(big);
  }else{
    const ph=cover.querySelector('.cover-ph');
    if(!ph)return false;
    prev.appendChild(ph.cloneNode(true));
  }
  const r=cover.getBoundingClientRect();
  const PW=230,PH=340;
  let left=r.right+14;
  if(left+PW>window.innerWidth-10) left=r.left-PW-14;
  if(left<10) left=10;
  let top=r.top+r.height/2-PH/2;
  top=Math.max(10,Math.min(top,window.innerHeight-PH-10));
  prev.style.left=left+'px';prev.style.top=top+'px';
  return true;
}
function showPreview(cover,pinned){
  if(previewPinned && !pinned) return;          // un hover no pisa una vista fijada con el dedo
  if(buildPreview(cover)===false) return;
  prev.classList.add('show');
  previewFor=cover; previewPinned=!!pinned;
}
function hidePreview(force){
  if(previewPinned && !force) return;            // un mouseleave suelto no cierra la vista fijada
  prev.classList.remove('show');
  previewPinned=false; previewFor=null;
}
function toggleTap(cover,e){                       // móvil: toca para abrir/cerrar la portada grande
  e.stopPropagation();
  if(previewPinned && previewFor===cover) hidePreview(true);
  else showPreview(cover,true);
}
document.addEventListener('click',()=>{ if(previewPinned) hidePreview(true); }); // tocar fuera cierra
window.addEventListener('scroll',()=>hidePreview(true),true);

refreshFilters();render();
